@Service
public class SalarySlipExtractor {
    private final ChatClient chatClient;
    private final BeanOutputConverter<SalarySlipExtract> converter;

    public SalarySlipExtractor(ChatClient.Builder builder) {
        converter = new BeanOutputConverter<>(SalarySlipExtract.class);
        chatClient = builder.defaultSystem("""
