import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.*;
import java.util.stream.Collectors;

record SlipText(String id, String content) {}
record BatchResult(List<SalarySlipExtract> highConfidence, List<SlipText> reviewQueue) {
    int totalProcessed() { return highConfidence.size() + reviewQueue.size(); }
}

@Service
class BatchDocumentProcessor {
    private final SalarySlipExtractor extractor;
    BatchDocumentProcessor(SalarySlipExtractor e) { extractor = e; }

    public BatchResult process(List<SlipText> documents) throws InterruptedException {
        List<SalarySlipExtract> highConf = new CopyOnWriteArrayList<>();
        List<SlipText> reviewQ = new CopyOnWriteArrayList<>();

        // Virtual threads: lightweight, one per document
        try (var executor = Executors.newVirtualThreadPerTaskExecutor()) {
            List<Future<?>> futures = documents.stream()
                .map(slip -> executor.submit(() -> {
                    Optional<SalarySlipExtract> result = extractor.extractSafe(slip.content());
                    if (result.isPresent()) highConf.add(result.get());
                    else reviewQ.add(slip);
                }))
                .collect(Collectors.toList());

            for (Future<?> f : futures) {
                try { f.get(30, TimeUnit.SECONDS); }
                catch (Exception e) { /* log and continue */ }
            }
        }
        return new BatchResult(highConf, reviewQ);
    }
}

@SpringBootTest
class BatchProcessorTest {
    @Autowired SalarySlipExtractor extractor;
    @Autowired BatchDocumentProcessor processor;

    @Test void batchTotal_equalInputCount() throws InterruptedException {
        // Use pre-built SalarySlipExtract records to simulate extraction results
        // (avoid real AI calls in unit tests)
        SalarySlipExtract highConf = new SalarySlipExtract("Raj", "Wipro", 8500000L, "2022-01-01", 92);
        SalarySlipExtract lowConf = new SalarySlipExtract(null, null, 0, null, 45);

        // Test the logic directly:
        List<SalarySlipExtract> highList = List.of(highConf);
        List<SlipText> reviewList = List.of(new SlipText("doc2", "illegible text"));
        BatchResult result = new BatchResult(highList, reviewList);
        assertEquals(2, result.totalProcessed());
    }
    @Test void highConf_and_review_split() {
        SalarySlipExtract high = new SalarySlipExtract("A", "B", 1000L, "2023-01-01", 85);
        SalarySlipExtract low = new SalarySlipExtract(null, null, 0, null, 55);
        assertTrue(high.isHighConfidence());
        assertFalse(low.isHighConfidence());
    }
}

