// Rule-based fallback (no AI required, always available):
@Service
class RuleBasedTicketClassifier {
    public String classify(String text) {
        String lower = text.toLowerCase();
        if (lower.contains("fraud") || lower.contains("unauthorized")) return "FRAUD_REPORT";
        if (lower.contains("refund") || lower.contains("money back")) return "REFUND_REQUEST";
        if (lower.contains("payment") && (lower.contains("failed") || lower.contains("declined"))) return "PAYMENT_FAILURE";
        if (lower.contains("account") && lower.contains("locked")) return "ACCOUNT_LOCKED";
        return "GENERAL_ENQUIRY";
    }
}

// AI service with graceful fallback:
@Service
class AIServiceWithFallback {
    private final RuleBasedTicketClassifier fallback;
    private boolean useAI = true; // toggle for testing

    AIServiceWithFallback(RuleBasedTicketClassifier f) { fallback = f; }

    void disableAI() { useAI = false; } // test helper

    public String classifyTicket(String ticketText) {
        if (!useAI) {
            return classifyWithFallback(ticketText, new RuntimeException("AI disabled"));
        }
        try {
            // In production: call ChatClient here
            // For test: simulate success path
            return "PAYMENT_FAILURE"; // simulated AI response
        } catch (Exception e) {
            return classifyWithFallback(ticketText, e);
        }
    }

    private String classifyWithFallback(String text, Exception reason) {
        // Log: AI unavailable, using fallback
        System.out.println("[FALLBACK] AI failed: " + reason.getMessage() + ". Using rule-based.");
        return fallback.classify(text);
    }
}

@SpringBootTest
class AiFallbackTest {
    @Autowired AIServiceWithFallback service;
    @Autowired RuleBasedTicketClassifier rules;

    @Test void primary_ai_works() {
        service.disableAI(); // force fallback to ensure predictable result
        String result = service.classifyTicket("My payment failed at checkout");
        assertNotNull(result);
        assertTrue(result.contains("PAYMENT") || result.contains("GENERAL"));
    }
    @Test void rule_based_works_standalone() {
        assertEquals("FRAUD_REPORT", rules.classify("unauthorized transaction on my account"));
        assertEquals("REFUND_REQUEST", rules.classify("I want my money back for the order"));
        assertEquals("GENERAL_ENQUIRY", rules.classify("what time does support open?"));
    }
}

