record LoanEligibilityResult(boolean eligible, String reason, long maxLoanAmountPaise) {
    static LoanEligibilityResult rejected(String reason) {
        return new LoanEligibilityResult(false, reason, 0);
    }
    static LoanEligibilityResult approved(long maxPaise) {
        return new LoanEligibilityResult(true, "Eligible", maxPaise);
    }
}

@Service
class LoanProcessor {
    // Eligibility rules (simplified HDFC home loan):
    // CIBIL >= 700, monthly income >= ₹25,000, max loan = 60× monthly income
    static final long MIN_INCOME_PAISE = 2_500_000L; // ₹25,000
    static final int MIN_CIBIL = 700;
    static final int LOAN_MULTIPLIER = 60;

    public LoanEligibilityResult process(LoanApplicationExtract extract) {
        if (!extract.isValid()) return LoanEligibilityResult.rejected("Incomplete extraction — human review required");
        if (extract.cibilScore() < MIN_CIBIL) return LoanEligibilityResult.rejected("CIBIL score " + extract.cibilScore() + " < minimum " + MIN_CIBIL);
        if (extract.monthlyGrossIncomePaise() < MIN_INCOME_PAISE) return LoanEligibilityResult.rejected("Monthly income below ₹25,000 minimum");
        long maxLoan = extract.monthlyGrossIncomePaise() * LOAN_MULTIPLIER;
        return LoanEligibilityResult.approved(maxLoan);
    }
}

@SpringBootTest
class LoanProcessorTest {
    @Autowired LoanProcessor processor;

    @Test void valid_extract_isValid() {
        var ext = new LoanApplicationExtract("Raj", "Wipro", 8_500_000L, "ABCDE1234F", 50_000_000L, 750, 90);
        assertTrue(ext.isValid()); assertTrue(ext.isHighConfidence());
    }
    @Test void lowCibil_rejected() {
        var ext = new LoanApplicationExtract("Raj", "Wipro", 8_500_000L, "ABCDE1234F", 50_000_000L, 650, 90);
        LoanEligibilityResult result = processor.process(ext);
        assertFalse(result.eligible()); assertTrue(result.reason().contains("CIBIL"));
    }
    @Test void goodApplicant_approved() {
        var ext = new LoanApplicationExtract("Priya", "Infosys", 10_000_000L, "PQRST9876Z", 100_000_000L, 780, 92);
        LoanEligibilityResult result = processor.process(ext);
        assertTrue(result.eligible());
        assertEquals(600_000_000L, result.maxLoanAmountPaise()); // 60 × ₹1,00,000 = ₹60,00,000
    }
}

