import java.util.*;

enum DocType { SALARY_SLIP, BANK_STATEMENT, ID_PROOF, INVOICE, UNKNOWN }

record DocClassification(DocType docType, int confidence) {}
record ExtractionResult(DocType docType, Map<String,String> fields, int confidence) {
    boolean isHighConfidence() { return confidence >= 70; }
}

@Service
class DocClassifier {
    // Rule-based classification (AI could do this too, but rules are cheaper):
    public DocClassification classify(String text) {
        String lower = text.toLowerCase();
        if (lower.contains("salary") || lower.contains("gross pay") || lower.contains("net pay")) return new DocClassification(DocType.SALARY_SLIP, 90);
        if (lower.contains("statement") && lower.contains("account")) return new DocClassification(DocType.BANK_STATEMENT, 88);
        if (lower.contains("aadhaar") || lower.contains("pan") || lower.contains("passport")) return new DocClassification(DocType.ID_PROOF, 85);
        if (lower.contains("invoice") || lower.contains("gst")) return new DocClassification(DocType.INVOICE, 82);
        return new DocClassification(DocType.UNKNOWN, 30);
    }
}

@Service
class DocExtractor {
    public ExtractionResult extract(DocType type, String text) {
        return switch (type) {
            case SALARY_SLIP -> new ExtractionResult(type, Map.of("type","salary","income","extracted"), 85);
            case BANK_STATEMENT -> new ExtractionResult(type, Map.of("type","bank","balance","extracted"), 80);
            case ID_PROOF -> new ExtractionResult(type, Map.of("type","id","pan","extracted"), 90);
            case INVOICE -> new ExtractionResult(type, Map.of("type","invoice","amount","extracted"), 75);
            default -> new ExtractionResult(type, Map.of(), 0);
        };
    }
}

@Service
class DocValidationService {
    private static final Map<DocType, Set<String>> REQUIRED = Map.of(
        DocType.SALARY_SLIP, Set.of("income"),
        DocType.ID_PROOF, Set.of("pan"),
        DocType.BANK_STATEMENT, Set.of("balance")
    );
    public boolean isValid(ExtractionResult result) {
        Set<String> required = REQUIRED.getOrDefault(result.docType(), Set.of());
        return result.isHighConfidence() && result.fields().keySet().containsAll(required);
    }
}

@SpringBootTest
class DocIntelligenceTest {
    @Autowired DocClassifier classifier;
    @Autowired DocExtractor extractor;
    @Autowired DocValidationService validator;

    @Test void classify_salary_slip() { assertEquals(DocType.SALARY_SLIP, classifier.classify("Monthly salary slip. Gross pay: ₹85,000.").docType()); }
    @Test void extract_routes_correctly() { var r=extractor.extract(DocType.ID_PROOF,"PAN: ABCDE1234F"); assertEquals(DocType.ID_PROOF,r.docType()); assertTrue(r.fields().containsKey("pan")); }
    @Test void valid_extraction_passes() { var r=extractor.extract(DocType.SALARY_SLIP,"salary"); assertTrue(validator.isValid(r)); }
    @Test void low_confidence_rejected() { var r=new ExtractionResult(DocType.SALARY_SLIP,Map.of("income","x"),45); assertFalse(validator.isValid(r)); }
}

