@Service
class WeeklyDigestGenerator {
    private final ChatClient chatClient;
    private final BeanOutputConverter<WeeklyDigest> converter;

    WeeklyDigestGenerator(ChatClient.Builder b) {
        converter = new BeanOutputConverter<>(WeeklyDigest.class);
        chatClient = b.defaultSystem("""
            You generate weekly market digests for Zerodha's retail investors.
            Write in simple English (avoid jargon).
            Use company common names (e.g., 'Reliance', not 'RELIANCE INDUSTRIES LIMITED').
            topStories: exactly 3 bullet points, max 30 words each.
            marketSentiment: BULLISH, BEARISH, or NEUTRAL based on overall events.
            riskAlert: one sentence about the biggest risk, or null if markets look stable.
            """).build();
    }

    public WeeklyDigest generate(List<MarketEvent> events) {
        String eventsText = events.stream()
            .map(e -> e.date() + " | " + e.symbol() + " | " + e.eventType() + ": " + e.description())
            .collect(java.util.stream.Collectors.joining("\n"));

        String response = chatClient.prompt()
            .user(u -> u.text("""
                Generate a weekly digest for {count} market events:
                {format}

                Events this week:
                {events}
                """)
                .param("count", events.size())
                .param("format", converter.getFormat())
                .param("events", eventsText))
            .call().content();
        WeeklyDigest digest = converter.convert(response);
        // Add events count (AI may not know exact count):
        return new WeeklyDigest(digest.topStories(), digest.marketSentiment(), digest.riskAlert(), events.size());
    }
}

