record SynthExtract(String name, long incomePaise, int confidence) {
    boolean highConfidence() { return confidence >= 70; }
}
record SynthTicket(String category, int urgency, boolean requiresHuman) {}

@Service class SynthDocClassifier {
    public String classify(String text) {
        String l = text.toLowerCase();
        if (l.contains("salary") || l.contains("gross pay")) return "SALARY_SLIP";
        if (l.contains("pan") || l.contains("aadhaar")) return "ID_PROOF";
        return "UNKNOWN";
    }
}

@Service class SynthExtractor {
    private final BeanOutputConverter<SynthExtract> conv = new BeanOutputConverter<>(SynthExtract.class);
    String schema() { return conv.getFormat(); }
    SynthExtract buildFromValues(String name, long income, int conf) { return new SynthExtract(name, income, conf); }
    Optional<SynthExtract> extractSafe(String name, long income, int conf) {
        SynthExtract r = new SynthExtract(name, income, conf);
        return r.highConfidence() ? Optional.of(r) : Optional.empty();
    }
}

@Service class SynthTicketClassifier {
    SynthTicket classify(String text) {
        String l = text.toLowerCase();
        boolean fraud = l.contains("fraud") || l.contains("unauthorized");
        int urgency = fraud ? 5 : l.contains("payment failed") ? 4 : l.contains("refund") ? 3 : 2;
        return new SynthTicket(fraud ? "FRAUD_REPORT" : "PAYMENT_FAILURE", urgency, urgency >= 4);
    }
}

